class Player:

    def __init__(self, name: str) -> None:
        self._id = uuid.uuid4()
        self.name = name
        self.items = []  # type: List[Item]

    @property
    def id_(self) -> uuid.UUID:
        return self._id


class Inventory:

    def __init__(self, player_id: uuid.UUID):
        self.player_id = player_id
        self.items = defaultdict(list)  # type: Dict[ItemType, List[Item]]

    async def transfer(
            self,
            item_id: int,
            target_player_id: Optional[uuid.UUID]
    ) -> Tuple[Optional[Item], Optional[Player]]:

        item = self._get_item(item_id)
        if not item or (target_player_id and target_player_id != self.player_id):
            return None, None

        target_player = await Player.get(target_player_id) \
            if target_player_id else None

        if target_player:
            self._remove_item(item)
            target_player.items.append(item)
        else:
            self._remove_item(item, True)

        return item, target_player

    def _get_item(self, item_id):
        for item in self.items[item_id]:
            if item.id == item_id:
                return item

    def _remove_item(self, item, remove_from_inventory=False):
        for item_list in self.items.values():
            try:
                item_list.remove(item)
            except ValueError:
                pass

        if not remove_from_inventory and isinstance(item, Item):
            self._add_item(item)

    def _add_item(self, item):
        self.items[item.type_.value].append(item)


class GameServer:
    players = {}  # type: Dict[uuid.UUID, Player]
    inventories = {}  # type: Dict[uuid.UUID, Inventory]

    async def handle_player_connection(self, websocket):
        player = await self._create_player()

        self.players[player.id_] = player
        self.inventories[player.id_] = Inventory(player.id_)

        try:
            async for message in websocket:
                data = json.loads(message)

                if 'action' not in data or \
                        data['action'] == 'get_inventory':
                    await self._send_inventory(websocket, player)

                    continue

                elif data['action'] == 'transfer':
                    item_id = int(data['item'])
                    target_player_id = uuid.UUID(bytes=data['targetPlayerId']) \
                        if 'targetPlayerId' in data else None

                    item, target_player = await self._transfer(
                        player,
                        item_id,
                        target_player_id)

                    if not item:
                        continue

                    await self._send_inventory(websocket, player)
                    await self._send_inventory(websocket, target_player)

                elif data['action'] == 'update':
                    self.players[player.id_] = Player(data['name'])

        except websockets.exceptions.ConnectionClosedError:
            pass

    async def _create_player(self):
        player = await Player.create()
        return player

    @staticmethod
    async def _transfer(player, item_id, target_player_id=None) -> Tuple[Optional[Item], Optional[Player]]:

        inventory = GameServer.inventories[player.id_]
        item, target_player = await inventory.transfer(item_id, target_player_id)

        return item, target_player

    async def _send_inventory(self, websocket, player):
        inventory = self.inventories[player.id_]
        items = [
            {
                'id': item.id_,
                'name': item.name,
                'type': item.type_.value
            } for item in inventory.items[item.type_.value]
        ]

        await websocket.send(json.dumps({
            'action': 'update',
            'playerId': player.id_.bytes,
            'items': items
        }))


